#include<bits/stdc++.h>
using namespace std;
int a[100010];
long long jc[100010],ny[100010];
const long long mod=998244353;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
long long C(long long n,long long m)
{
    return jc[n]*ny[m]%mod*ny[n-m]%mod;
}
int main()
{
    jc[0]=ny[0]=1;
    for(int i=1;i<=100000;i++)
    {
        jc[i]=jc[i-1]*i%mod;
    }
    ny[100000]=fastpow(jc[100000],mod-2);
    for(int i=99999;i>=1;i--)
    {
        ny[i]=ny[i+1]*(i+1)%mod;
    }
    int n,m,k;
    scanf("%d%d%d",&n,&m,&k);
    long long ans=1;
    for(int i=1;i<=m;i++)
    {
        scanf("%d",&a[i]);
        if(n-a[i]<k)
        {
            ans=0;
            break;
        }
        ans=ans*(C(n-k,a[i])*fastpow(C(n,a[i]),mod-2)%mod)%mod;
    }
    printf("%lld",ans);
    return 0;
}
